export const code = async (inputs) => {
  const params = inputs.params.body?.data || {
    webhookBaseUrl: 'http://localhost:4200/api/v1/webhooks',
    workflows: [],
    cleanupWorkflows: [],
    accounts: [],
    regions: [],
  };

  return params;
};

import dayjs from 'dayjs';

export const code = async (inputs) => {
  const now = dayjs();
  const firstDay = now.subtract(6, 'month').startOf('month').format('YYYY-MM-DD');
  const lastDay = now.subtract(1, 'month').endOf('month').format('YYYY-MM-DD');

  return {
    firstDay,
    lastDay,
  };
};

// @ts-nocheck
// ── Workflow-to-Category Mapping ──────────────────────────────────────────────

const WORKFLOW_CATEGORIES = {
  // idle: resource is unused, recommend termination/deletion
  'AWS Benchmark - Idle RDS instances': 'idle',
  'AWS Benchmark - Underutilized EC2': 'idle',
  'AWS Benchmark - Underutilized RDS': 'idle',
  'AWS Benchmark - Idle Elastic Load Balancer (ELB)': 'idle',
  'AWS Benchmark - Unused NAT Gateways': 'idle',
  'AWS Benchmark - Underutilized VPC Interface Endpoints': 'idle',
  'AWS Benchmark - Unattached Elastic IP Addresses': 'idle',
  'AWS Benchmark - Unattached EBS': 'idle',
  'AWS Benchmark - Idle Compute Optimizer Recommendations': 'idle',

  // rightsizing: resource is over-provisioned, recommend downsizing
  'AWS Benchmark - EC2 Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - RDS Instance Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - RDS Storage Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - EBS Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - ECS Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - Lambda Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - ASG Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - License Compute Optimizer Recommendations': 'rightsizing',
  'AWS Benchmark - DynamoDB Over-Provisioned Tables': 'rightsizing',

  // migration: resource should be migrated/upgraded
  'AWS Benchmark - Migrate EC2 instances to Graviton': 'migration',
  'AWS Benchmark - EBS Generation upgrade (gp2 to gp3)': 'migration',
  'AWS Benchmark - RDS Extended Support Avoidance': 'migration',

  // cleanup: orphaned resources
  'AWS Benchmark - Orphaned RDS Snapshots': 'cleanup',
};

// ── Default Config ───────────────────────────────────────────────────────────

const DEFAULT_CONFIG = {
  // 'higher_savings' | 'prefer_compute_optimizer' | 'prefer_openops'
  winnerStrategy: 'higher_savings',

  // When savings are equal and strategy is 'higher_savings', prefer this source
  tieBreaker: 'compute_optimizer', // 'compute_optimizer' | 'openops'

  // If true, idle recommendations supersede all other categories for the same resource
  idleTrumpsAll: true,

  // Enable debug mode — adds explanation for each decision
  debug: false,

  // Override the workflow-to-category mapping (null = use defaults)
  workflowCategories: null,
};

// ── Helpers ──────────────────────────────────────────────────────────────────

const parseSavings = (opportunity) =>
  parseFloat(opportunity['Estimated savings USD per month']) || 0;

const isComputeOptimizer = (workflow) =>
  workflow.includes('Compute Optimizer');

const getCategory = (workflow, config) => {
  const categories = config.workflowCategories || WORKFLOW_CATEGORIES;
  return categories[workflow] || 'unknown';
};

const briefOpp = (opp) => ({
  id: opp.id,
  workflow: opp['Workflow'],
  savings: parseSavings(opp),
});

// ── Winner Selection ─────────────────────────────────────────────────────────

const selectWinner = (opportunities, config) => {
  if (opportunities.length === 1) {
    return { winners: [opportunities[0]], losers: [], reason: 'Only one opportunity in category' };
  }

  const strategy = config.winnerStrategy || 'higher_savings';

  let sorted;

  if (strategy === 'prefer_compute_optimizer') {
    sorted = [...opportunities].sort((a, b) => {
      const aCO = isComputeOptimizer(a['Workflow']) ? 1 : 0;
      const bCO = isComputeOptimizer(b['Workflow']) ? 1 : 0;
      if (bCO !== aCO) return bCO - aCO;
      return parseSavings(b) - parseSavings(a);
    });
  } else if (strategy === 'prefer_openops') {
    sorted = [...opportunities].sort((a, b) => {
      const aOO = isComputeOptimizer(a['Workflow']) ? 0 : 1;
      const bOO = isComputeOptimizer(b['Workflow']) ? 0 : 1;
      if (bOO !== aOO) return bOO - aOO;
      return parseSavings(b) - parseSavings(a);
    });
  } else {
    // higher_savings (default)
    sorted = [...opportunities].sort((a, b) => {
      const diff = parseSavings(b) - parseSavings(a);
      if (diff !== 0) return diff;
      // tie-break
      const preferCO = (config.tieBreaker || 'compute_optimizer') === 'compute_optimizer';
      const aCO = isComputeOptimizer(a['Workflow']) ? 1 : 0;
      const bCO = isComputeOptimizer(b['Workflow']) ? 1 : 0;
      return preferCO ? bCO - aCO : aCO - bCO;
    });
  }

  const winner = sorted[0];
  const losers = sorted.slice(1);

  const reason = buildWinnerReason(strategy, winner, losers, config);

  return { winners: [winner], losers, reason };
};

const buildWinnerReason = (strategy, winner, losers, config) => {
  const wSavings = parseSavings(winner);
  const lDescriptions = losers
    .map((l) => `$${parseSavings(l).toFixed(2)} (${l['Workflow']})`)
    .join(', ');

  if (strategy === 'prefer_compute_optimizer') {
    return `Strategy: prefer Compute Optimizer. Winner: ${winner['Workflow']} ($${wSavings.toFixed(2)}) over ${lDescriptions}`;
  }
  if (strategy === 'prefer_openops') {
    return `Strategy: prefer OpenOps. Winner: ${winner['Workflow']} ($${wSavings.toFixed(2)}) over ${lDescriptions}`;
  }

  const allSame = losers.every((l) => parseSavings(l) === wSavings);
  if (allSame) {
    const tieLabel =
      (config.tieBreaker || 'compute_optimizer') === 'compute_optimizer'
        ? 'Compute Optimizer'
        : 'OpenOps';
    return `Equal savings ($${wSavings.toFixed(2)}). Tie-break: prefer ${tieLabel}. Winner: ${winner['Workflow']} over ${lDescriptions}`;
  }

  return `Higher savings: $${wSavings.toFixed(2)} (${winner['Workflow']}) over ${lDescriptions}`;
};

// ── Core Deduplication ───────────────────────────────────────────────────────

const deDuplicate = (opportunities, config) => {
  const toKeep = [];
  const toRemove = [];
  const debugLog = [];

  // 0. Remove opportunities with 0 USD savings
  const nonZeroOpportunities = [];
  for (const opp of opportunities) {
    if (parseSavings(opp) === 0) {
      toRemove.push(opp);
      if (config.debug) {
        debugLog.push({
          resourceId: opp['Resource Id'],
          action: 'zero_savings_removed',
          kept: [],
          removed: [briefOpp(opp)],
          reason: 'Opportunity has $0 estimated savings — removed',
        });
      }
    } else {
      nonZeroOpportunities.push(opp);
    }
  }

  // 1. Group by Resource Id
  const groups = new Map();
  for (const opp of nonZeroOpportunities) {
    const resourceId = opp['Resource Id'];
    if (!groups.has(resourceId)) {
      groups.set(resourceId, []);
    }
    groups.get(resourceId).push(opp);
  }

  // 2. Process each resource group
  for (const [resourceId, opps] of groups) {
    if (opps.length === 1) {
      toKeep.push(opps[0]);
      if (config.debug) {
        debugLog.push({
          resourceId,
          action: 'unique_resource',
          kept: [briefOpp(opps[0])],
          removed: [],
          reason: 'Only opportunity for this resource — auto-kept',
        });
      }
      continue;
    }

    // 3. Sub-group by category
    const categoryGroups = new Map();
    for (const opp of opps) {
      const category = getCategory(opp['Workflow'], config);
      if (!categoryGroups.has(category)) {
        categoryGroups.set(category, []);
      }
      categoryGroups.get(category).push(opp);
    }

    // 4. Select winner within each category
    const categoryWinners = new Map(); // category -> winners[]
    for (const [category, categoryOpps] of categoryGroups) {
      const { winners, losers, reason } = selectWinner(categoryOpps, config);
      categoryWinners.set(category, winners);
      toRemove.push(...losers);

      if (config.debug && losers.length > 0) {
        debugLog.push({
          resourceId,
          action: 'selected_winner',
          category,
          kept: winners.map(briefOpp),
          removed: losers.map(briefOpp),
          reason,
        });
      }
    }

    // 5. Apply cross-category rules: idle trumps all other categories
    if (config.idleTrumpsAll && categoryWinners.has('idle')) {
      for (const [cat, winners] of categoryWinners) {
        if (cat === 'idle') continue;
        toRemove.push(...winners);
        categoryWinners.delete(cat);

        if (config.debug) {
          debugLog.push({
            resourceId,
            action: 'idle_trumps_all',
            kept: categoryWinners.get('idle').map(briefOpp),
            removed: winners.map(briefOpp),
            reason: `Idle recommendation supersedes ${cat} — resource should be terminated/deleted, not optimized`,
          });
        }
      }
    }

    // 6. Collect all surviving winners
    for (const winners of categoryWinners.values()) {
      toKeep.push(...winners);
    }
  }

  const result = {
    toKeep,
    toRemove,
    toKeepCount: toKeep.length,
    toRemoveCount: toRemove.length,
  };
  if (config.debug) {
    result.debugLog = debugLog;
  }
  return result;
};

// ── Entry Point ──────────────────────────────────────────────────────────────

export const code = async ({ opportunities }) => {
  const config = { ...DEFAULT_CONFIG };
  return deDuplicate(opportunities, config);
};

// ── Named Exports for Testing ────────────────────────────────────────────────

export {
  deDuplicate,
  selectWinner,
  getCategory,
  isComputeOptimizer,
  parseSavings,
  WORKFLOW_CATEGORIES,
  DEFAULT_CONFIG,
};
